-- Seed the sandbox + malgovia campaigns as pure DB campaigns.
--
-- Until now these two ran as CODE contexts (campaignData/sandbox.ts,
-- campaignData/malgovia/) that the engine resolved directly. The campaign
-- platform resolves every campaign as DB rows overlaid on the SRD base
-- template, so this migration plants sandbox + malgovia as ordinary rows —
-- the last step before the per-campaign code is deleted (one loading path).
--
-- The payloads were produced by scripts/serializeCampaign.ts, which writes a
-- code Context through the content API's put* functions and proves the result
-- resolves over the base template byte-identical to the code context. To
-- regenerate after a content change:
--
--   docker compose exec backend npx tsx scripts/serializeCampaign.ts sandbox malgovia
--   bash scripts/gen-seed-032.sh   (the generator that emitted the block below)
--
-- Idempotency (this file is double-applied on fresh environments — CI initdb
-- then the migration runner): the campaigns rows UPSERT (refreshing only
-- `data`, so a later rename/visibility change survives re-apply), and all
-- relational + custom content is DELETE-then-INSERT scoped to the two ids
-- (replace-all, children before parents per the FK order). sandbox is seeded
-- private (it launches via /?campaign=sandbox, matching the old hidden flag);
-- malgovia is global.

-- campaigns (upsert: keep name/visibility/name_overridden on re-apply; only data refreshes)
ON CONFLICT (id) DO UPDATE SET data = EXCLUDED.data;
ON CONFLICT (id) DO UPDATE SET data = EXCLUDED.data;

-- wipe + reseed all relational/custom content for the two campaigns (replace-all = double-apply safe; children before parents)
DELETE FROM campaign_region_sites  WHERE campaign_id IN ('sandbox','malgovia');
DELETE FROM campaign_town_venues   WHERE campaign_id IN ('sandbox','malgovia');
DELETE FROM campaign_regions       WHERE campaign_id IN ('sandbox','malgovia');
DELETE FROM campaign_towns         WHERE campaign_id IN ('sandbox','malgovia');
DELETE FROM campaign_rooms         WHERE campaign_id IN ('sandbox','malgovia');
DELETE FROM campaign_custom_items  WHERE campaign_id IN ('sandbox','malgovia');
DELETE FROM campaign_custom_monsters WHERE campaign_id IN ('sandbox','malgovia');

