INSERT INTO campaigns (id, name, visibility, data, name_overridden) VALUES ('malgovia', 'Malgovia', 'global', E'{"rules": [{"name": "guild_ledger_found", "once": true, "priority": 5, "conditions": {"all": [{"fact": "loot_taken", "value": "guild_ledger", "operator": "contains"}, {"fact": "flags", "value": "rule_fired_guild_ledger_found", "operator": "doesNotContain"}]}, "consequences": [{"type": "advance_quest", "stepId": "step_find_ledger", "questId": "quest_shipment"}, {"text": "You recognise the Guild''s stamp on the waterlogged ledger — this is what Aldric was looking for.", "type": "add_narrative"}]}, {"name": "halden_locket_found", "once": true, "priority": 5, "conditions": {"all": [{"fact": "loot_taken", "value": "halden_locket", "operator": "contains"}, {"fact": "flags", "value": "rule_fired_halden_locket_found", "operator": "doesNotContain"}]}, "consequences": [{"type": "advance_quest", "stepId": "step_find_locket", "questId": "quest_trapper"}, {"text": "You recognise the engraving — Halden''s daughter''s name. The cult had him here.", "type": "add_narrative"}]}, {"name": "cult_idol_recovered", "once": true, "priority": 5, "conditions": {"all": [{"fact": "loot_taken", "value": "cult_idol", "operator": "contains"}, {"fact": "flags", "value": "rule_fired_cult_idol_recovered", "operator": "doesNotContain"}]}, "consequences": [{"type": "advance_quest", "stepId": "step_recover_idol", "questId": "quest_cult"}, {"text": "The idol grows cold in your hand. Captain Riese will want to see this immediately.", "type": "add_narrative"}]}, {"name": "step_talk_elise", "once": true, "conditions": {"all": [{"any": [{"fact": "action", "value": "talk_response", "operator": "equal"}, {"fact": "action", "value": "accept_quest", "operator": "equal"}]}, {"fact": "room_id", "value": "pinegate_square", "operator": "equal"}, {"fact": "npc_id", "value": "npc_elise_elder", "operator": "equal"}]}, "consequences": []}], "quests": [{"id": "quest_arrival", "desc": "Months on the road have left the party restless, and the pine-dark hills of Malgovia finally rise ahead. Word on the road said the village of Pinegate, at the vale''s southern edge, needs capable hands — and where there''s trouble, there''s coin. Make your way to Pinegate.", "steps": [{"id": "step_reach_pinegate", "desc": "Travel to the village of Pinegate.", "condition": {"all": [{"fact": "current_town_id", "value": "pinegate_town", "operator": "equal"}]}}], "title": "The Road to Pinegate", "rewards": [{"type": "give_xp", "amount": 50}, {"text": "Pinegate''s lanterns flicker a wary welcome. By the well, an old woman watches you approach — she has the look of someone with a problem worth coin.", "type": "add_narrative"}], "startActive": true}, {"id": "quest_shipment", "desc": "The Merchant Guild''s supply wagons vanished on the Old Road. Find the Guild Ledger in the crypt and return it to Aldric.", "steps": [{"id": "step_talk_aldric", "desc": "Speak with Aldric the Merchant to learn about the missing shipment.", "condition": {"all": [{"fact": "room_id", "value": "millhaven_market", "operator": "equal"}, {"any": [{"fact": "action", "value": "talk_response", "operator": "equal"}, {"fact": "action", "value": "accept_quest", "operator": "equal"}]}]}}, {"id": "step_find_ledger", "desc": "Find the Guild Ledger in the Shattered Crypt.", "condition": {"all": [{"fact": "loot_taken", "value": "guild_ledger", "operator": "contains"}]}}, {"id": "step_return_ledger", "desc": "Return the ledger to Aldric in the Merchant District.", "condition": {"all": [{"fact": "loot_taken", "value": "guild_ledger", "operator": "contains"}, {"fact": "room_id", "value": "millhaven_market", "operator": "equal"}]}}], "title": "The Missing Shipment", "repGain": 20, "rewards": [{"text": "Aldric leafs through the waterlogged pages. \\"This is it — proof the wagons were never delivered.\\" He presses a purse into your hand and marks the Guild''s books with your name.", "type": "add_narrative"}, {"type": "consume_item", "itemId": "guild_ledger"}, {"type": "give_gold", "amount": 150}, {"type": "give_xp", "amount": 300}], "factionId": "faction_guild", "giverNpcId": "npc_aldric"}, {"id": "quest_crypt", "desc": "Sister Maren of the Temple of Selûne needs the Crypt Lord destroyed and the Moonstone Amulet recovered.", "steps": [{"id": "step_learn_crypt", "desc": "Learn about the threat in the Shattered Crypt from Sister Maren.", "condition": {"all": [{"fact": "room_id", "value": "millhaven_temple", "operator": "equal"}, {"any": [{"fact": "action", "value": "talk_response", "operator": "equal"}, {"fact": "action", "value": "accept_quest", "operator": "equal"}]}]}}, {"id": "step_kill_lord", "desc": "Defeat the Crypt Lord in the Throne of the Dead.", "condition": {"all": [{"fact": "enemies_killed", "value": "dungeon_crypt_throne#0", "operator": "contains"}]}}, {"id": "step_recover_amulet", "desc": "Recover the Moonstone Amulet from the crypt.", "condition": {"all": [{"fact": "loot_taken", "value": "moonstone_amulet", "operator": "contains"}]}}], "title": "Beneath the Surface", "rewards": [{"type": "give_gold", "amount": 200}, {"type": "give_xp", "amount": 1500}, {"type": "modify_hp", "amount": 20}, {"text": "Sister Maren places her hands on your shoulders and speaks a blessing of Selûne. You feel wounds close and strength return.", "type": "add_narrative"}], "giverNpcId": "npc_sister_maren"}, {"id": "quest_shadow", "desc": "Dusk in the Lantern District has evidence that Captain Vane is corrupt. Find the incriminating letter in the garrison strongbox.", "steps": [{"id": "step_meet_dusk", "desc": "Meet Dusk in the Lantern District.", "condition": {"all": [{"fact": "room_id", "value": "millhaven_lantern", "operator": "equal"}, {"any": [{"fact": "action", "value": "talk_response", "operator": "equal"}, {"fact": "action", "value": "accept_quest", "operator": "equal"}]}]}}, {"id": "step_find_letter", "desc": "Retrieve the incriminating letter from the garrison.", "condition": {"all": [{"fact": "loot_taken", "value": "shadow_evidence", "operator": "contains"}]}}, {"id": "step_deliver_letter", "desc": "Deliver the letter to Dusk.", "condition": {"all": [{"fact": "loot_taken", "value": "shadow_evidence", "operator": "contains"}, {"fact": "room_id", "value": "millhaven_lantern", "operator": "equal"}]}}], "title": "Shadow Dealings", "repGain": -10, "rewards": [{"type": "give_gold", "amount": 75}, {"type": "give_xp", "amount": 200}, {"text": "Dusk takes the letter with a tight smile. \\"Captain Vane''s days are numbered. You''ve made some useful friends today.\\"", "type": "add_narrative"}], "factionId": "faction_watch", "giverNpcId": "npc_dusk"}, {"id": "quest_trapper", "desc": "Old Halden the trapper has been missing three days. Innkeeper Brann wants him back — or proof of his fate. His silver locket should be enough.", "steps": [{"id": "step_talk_brann", "desc": "Speak with Innkeeper Brann about the missing trapper.", "condition": {"all": [{"fact": "room_id", "value": "pines_tavern", "operator": "equal"}, {"any": [{"fact": "action", "value": "talk_response", "operator": "equal"}, {"fact": "action", "value": "accept_quest", "operator": "equal"}]}]}}, {"id": "step_find_locket", "desc": "Find Halden''s locket in the Iceshard Spire.", "condition": {"all": [{"fact": "loot_taken", "value": "halden_locket", "operator": "contains"}]}}, {"id": "step_return_locket", "desc": "Return the locket to Innkeeper Brann at the Pine Tavern.", "condition": {"all": [{"fact": "loot_taken", "value": "halden_locket", "operator": "contains"}, {"fact": "room_id", "value": "pines_tavern", "operator": "equal"}]}}], "title": "The Missing Trapper", "repGain": 10, "rewards": [{"type": "give_gold", "amount": 80}, {"type": "give_xp", "amount": 250}, {"text": "Brann presses a purse of 80 gold into your hand and bows his head. \\"His daughter will rest easier knowing.\\"", "type": "add_narrative"}], "factionId": "faction_wardens", "giverNpcId": "npc_brann"}, {"id": "quest_cult", "desc": "Captain Riese has charged you with breaking the Frostspire Cult: kill the Frost Acolyte and bring back their idol.", "steps": [{"id": "step_meet_riese", "desc": "Speak with Captain Riese at the Warden Post.", "condition": {"all": [{"fact": "room_id", "value": "pines_warden", "operator": "equal"}, {"any": [{"fact": "action", "value": "talk_response", "operator": "equal"}, {"fact": "action", "value": "accept_quest", "operator": "equal"}]}]}}, {"id": "step_kill_acolyte", "desc": "Defeat the Frost Acolyte at the Ritual Apex.", "condition": {"all": [{"fact": "enemies_killed", "value": "spire_ritual_apex#boss", "operator": "contains"}]}}, {"id": "step_recover_idol", "desc": "Recover the Frostspire Idol.", "condition": {"all": [{"fact": "loot_taken", "value": "cult_idol", "operator": "contains"}]}}], "title": "Silence the Spire", "repGain": 30, "rewards": [{"type": "give_gold", "amount": 250}, {"type": "give_xp", "amount": 1500}, {"type": "modify_hp", "amount": 15}, {"text": "Captain Riese turns the idol in her hands, then drops it into the brazier. \\"For a generation, then. Drink with us tonight.\\"", "type": "add_narrative"}], "factionId": "faction_wardens", "giverNpcId": "npc_riese"}, {"id": "quest_silent_grove", "desc": "Old Elise needs someone to walk Mareth''s path: reach the Ancient Oak, defeat the Fey Trickster that silenced her, and recover the Oak''s heart.", "steps": [{"id": "step_talk_elise", "desc": "Speak with Old Elise in Pinegate Square.", "condition": {"all": [{"fact": "flags", "path": "$.rule_fired_step_talk_elise", "value": true, "operator": "equal"}]}}, {"id": "step_take_charm", "desc": "Take Mareth''s Charm from the Burnt Stump lodge.", "condition": {"all": [{"fact": "loot_taken", "value": "circle_charm", "operator": "contains"}]}}, {"id": "step_reach_oak", "desc": "Reach the Ancient Oak at the grove''s heart.", "condition": {"all": [{"fact": "visited_rooms", "value": "ancient_oak", "operator": "contains"}]}}, {"id": "step_defeat_trickster", "desc": "Defeat the Fey Trickster at the heart of the grove.", "condition": {"all": [{"fact": "enemies_killed", "value": "ancient_oak#0", "operator": "contains"}]}}, {"id": "step_take_heart", "desc": "Recover the Heart of the Ancient Oak from the grove sanctum.", "condition": {"all": [{"fact": "loot_taken", "value": "oak_heart", "operator": "contains"}]}}], "title": "The Silent Grove", "repGain": 45, "rewards": [{"type": "give_gold", "amount": 400}, {"type": "give_xp", "amount": 1850}, {"text": "Old Elise presses your hand in both of hers. ''The Verdant Circle remembers you.'' The grove sighs — a long, green release; Pinegate will sleep easy tonight.", "type": "add_narrative"}], "factionId": "faction_verdant", "giverNpcId": "npc_elise_elder"}], "factions": [{"id": "faction_guild", "name": "Merchant Guild", "thresholds": {"exalted": 60, "hostile": -50, "neutral": 0, "friendly": 20, "unfriendly": -10}, "shopPriceModifiers": {"exalted": 0.75, "hostile": 1.5, "neutral": 1, "friendly": 0.9, "unfriendly": 1.2}}, {"id": "faction_watch", "name": "City Watch", "thresholds": {"exalted": 60, "hostile": -50, "neutral": 0, "friendly": 20, "unfriendly": -10}, "shopPriceModifiers": {"exalted": 1, "hostile": 1, "neutral": 1, "friendly": 1, "unfriendly": 1}}, {"id": "faction_wardens", "name": "Pine Wardens", "thresholds": {"exalted": 60, "hostile": -50, "neutral": 0, "friendly": 20, "unfriendly": -10}, "shopPriceModifiers": {"exalted": 0.7, "hostile": 1.5, "neutral": 1, "friendly": 0.85, "unfriendly": 1.2}}, {"id": "faction_verdant", "name": "Verdant Circle", "thresholds": {"exalted": 60, "hostile": -50, "neutral": 0, "friendly": 20, "unfriendly": -10}, "shopPriceModifiers": {"exalted": 0.7, "hostile": 1.5, "neutral": 1, "friendly": 0.85, "unfriendly": 1.2}}], "gameStart": "You''ve been on the road for months, and the party grows restless as the pine-dark hills of Malgovia finally rise ahead. Somewhere back along the way you caught word: the village of Pinegate needs help, and is willing to pay. Itching for action and coin, you turn off the road toward town — and the deeper troubles of the vale that wait beyond it: a market town and its restless crypt to the east, and, far to the north, the cult festering in Iceshard Spire. Start small. The vale grows colder, and crueler, the farther you walk.", "worldName": "Malgovia", "narratives": {"noLoot": ["There is nothing of value here.", "The area has already been stripped clean."], "levelUp": ["Your trials have made you stronger — you have reached level {level}!", "Experience crystallizes into power — you advance to level {level}!"], "noEnemy": ["There is no enemy here to fight.", "The area is clear."], "killShot": ["{The_enemy} collapses, broken and still.", "{The_enemy} falls — the threat is ended.", "With a final blow, {the_enemy} is destroyed."], "longRest": ["The party makes camp and rests through the night."], "combatHit": {"hurt": ["Despite your wounds, you land a telling blow on {the_enemy}.", "Gritting through the pain, your attack finds {the_enemy}.", "Desperate and determined, your strike connects with {the_enemy}."], "healthy": ["With fluid confidence, {The_enemy} reels from the blow.", "Your attack connects cleanly — {the_enemy} staggers.", "A solid strike lands on {the_enemy}."], "critical": ["Barely standing, you somehow find the strength to strike {the_enemy}.", "On sheer will alone, your blow hammers {the_enemy}."]}, "shortRest": ["You tend your wounds and catch your breath."], "classStyle": {"Bard": ["with unexpected flair", "using the enemy''s own momentum"], "Rogue": ["from the shadows", "finding the weak point", "with practiced ease"], "Cleric": ["invoking divine strength", "guided by faith"], "Ranger": ["with ranger''s instinct", "reading the enemy''s stance"], "Wizard": ["channeling arcane energy through the strike", "with focused concentration"], "Fighter": ["with disciplined precision", "using superior technique", "exploiting a gap in their guard"], "Paladin": ["with holy conviction", "driven by sacred oath"]}, "combatMiss": {"hurt": ["Pain throws off your aim — {the_enemy} avoids it.", "Your wounded arm betrays you; {the_enemy} steps aside."], "healthy": ["Your strike glances off {the_enemy}''s guard.", "{The_enemy} sidesteps neatly.", "Your blow goes wide."], "critical": ["You can barely lift your weapon — the attack fails entirely.", "{The_enemy} brushes aside your feeble attempt."]}, "deathLines": ["{name} falls, life fading...", "{name} collapses — not long now..."], "alreadyDead": ["That foe is already defeated."], "combatStart": ["{The_enemy} bars your path — initiative is drawn!", "Combat begins! {The_enemy} readies for battle."], "roomArrival": {"pinegate_lodge": ["The lodge is warm with woodsmoke; a fire crackles in the hearth, and Mareth’s carved charm hangs on the far wall.", "Conversation lulls as you duck into the common-hall. The fire pops, and the timber walls smell of pine and old ale.", "Lamplight and hearth-glow fill the Burnt Stump; benches scrape as folk make room at the long tables."], "millhaven_square": ["The Old Road brings you to the edge of Malgovia. Millhaven''s lantern-lit walls stand to the east; the wooded hills past it hide the bandit camp and the Shattered Crypt. Your map of the vale lies open before you."], "dungeon_crypt_exit": ["A shaft of pale light falls from above — the entrance to the crypt, and freedom beyond."], "dungeon_crypt_entrance": ["Mossy steps lead down into the Shattered Crypt. Cold air breathes from the darkness below.", "The iron doors of the crypt hang ajar, groaning softly. Torchlight flickers from within."]}, "weaponVerbs": {"mace": ["smashes", "bludgeons", "cracks"], "rapier": ["pierces", "lunges", "skewers"], "longbow": ["pins", "skewers", "pierces"], "unarmed": ["punches", "strikes", "slams"], "longsword": ["cleaves", "slashes", "cuts"], "shortsword": ["thrusts", "stabs", "jabs"], "quarterstaff": ["strikes", "sweeps", "clubs"]}, "enemyAttacks": ["{The_enemy} attacks!", "{The_enemy} strikes at you!", "{The_enemy} presses the assault!"], "lootPickedUp": ["You pocket the {item}.", "The {item} joins your inventory.", "You take the {item}."], "sneakSuccess": ["You slip into the shadows undetected.", "Moving like a ghost, you disappear from sight."], "alreadyLooted": ["You have already taken what was here."], "enemyDeflected": ["{The_enemy}''s blow glances off your armor.", "{The_enemy} attacks but finds no opening.", "You turn aside {the_enemy}''s strike."], "enemyReactions": {"Shadow": ["It writhes and contracts.", "The darkness disperses briefly.", "A hollow wail echoes."], "Crypt Lord": ["THAT is merely an annoyance to me.", "The lich king laughs — a sound like cracking ice.", "Ancient power radiates from its wounds."], "Crypt Ghoul": ["It shrieks with unnatural fury.", "The wound steams with cold ichor.", "It snaps its jaws in pain."], "Bandit Ruffian": ["It curses under its breath.", "Blood soaks its tunic.", "It stumbles back a step."], "Skeleton Warrior": ["Its bones rattle with the impact.", "Ancient dust shakes from its frame.", "It staggers but keeps fighting."]}, "genericArrival": ["The shadows shift as you enter.", "Dust motes drift in the pale torchlight.", "Something skitters in the darkness.", "An eerie silence greets you."], "deathSaveStatus": {"1": ["You cling to life by a thread.", "Darkness crowds the edges of your vision."], "2": ["Death whispers your name.", "The world grows very cold."], "3": ["You are beyond help now."]}}, "backgrounds": [{"id": "soldier", "desc": "You served in a regional militia or under a noble banner.", "name": "Soldier", "feature": "Military Rank", "language": "Common", "originFeat": "savage_attacker", "featureDesc": "Local watchmen and veterans recognise your authority.", "toolProficiency": "Gaming set", "skillProficiencies": ["athletics", "intimidation"], "abilityScoreIncreases": ["str", "dex", "con"]}, {"id": "criminal", "desc": "You have a history of breaking the law.", "name": "Criminal", "feature": "Criminal Contact", "language": "Thieves'' Cant", "originFeat": "alert", "featureDesc": "A reliable contact in the Lantern District handles fences and rumour.", "toolProficiency": "Thieves'' Tools", "skillProficiencies": ["stealth", "deception"], "abilityScoreIncreases": ["dex", "con", "int"]}, {"id": "sage", "desc": "You spent years studying lore and arcane history.", "name": "Sage", "feature": "Researcher", "language": "Common", "originFeat": "magic_initiate_arcane", "featureDesc": "If you do not know information, you know where to find it.", "toolProficiency": "Calligrapher''s Tools", "skillProficiencies": ["arcana", "history"], "abilityScoreIncreases": ["con", "int", "wis"]}, {"id": "acolyte", "desc": "You served at the Temple of Selûne before taking up the road.", "name": "Acolyte", "feature": "Shelter of the Faithful", "language": "Celestial", "originFeat": "magic_initiate_divine", "featureDesc": "You and your companions receive healing and care at temples.", "toolProficiency": "Calligrapher''s Tools", "skillProficiencies": ["religion", "insight"], "abilityScoreIncreases": ["int", "wis", "cha"]}], "classSpells": {"Bard": ["bardic_inspiration_spell", "cure_wounds", "healing_word", "charm_person", "sleep"], "Druid": ["shillelagh", "entangle", "cure_wounds", "healing_word"], "Cleric": ["sacred_flame", "cure_wounds", "guiding_bolt", "hold_person", "bless", "spiritual_weapon", "healing_word", "animate_dead"], "Wizard": ["fire_bolt", "magic_missile", "hold_person", "thunderwave", "misty_step", "fireball", "animate_dead"], "Paladin": ["divine_smite_spell", "cure_wounds", "bless"], "Warlock": ["eldritch_blast", "hex", "charm_person"], "Sorcerer": ["fire_bolt", "sleep", "burning_hands", "misty_step", "fireball"]}, "recommendedParty": {"size": 4, "composition": ["Fighter", "Cleric", "Rogue", "Wizard"]}, "classStartingLoot": {"Bard": ["rapier", "leather_armor"], "Monk": ["shortsword", "dart"], "Druid": ["quarterstaff", "leather_armor", "healing_potion"], "Rogue": ["shortsword", "leather_armor"], "Cleric": ["mace", "scale_mail", "shield", "holy_symbol"], "Ranger": ["shortsword", "longbow", "leather_armor"], "Wizard": ["quarterstaff", "component_pouch"], "Fighter": ["longsword", "chain_mail", "shield"], "Paladin": ["longsword", "chain_mail", "shield"], "Warlock": ["dagger", "leather_armor", "healing_potion"], "Sorcerer": ["dagger", "component_pouch", "healing_potion"], "Barbarian": ["greataxe", "handaxe", "healing_potion"]}, "classStartingEquipment": {"Bard": [{"id": "A", "gold": 19, "items": ["leather_armor", "dagger", "dagger"], "label": "Leather & daggers"}, {"id": "B", "gold": 90, "items": [], "label": "Gold only"}], "Monk": [{"id": "A", "gold": 11, "items": ["quarterstaff", "dagger", "dagger"], "label": "Staff & daggers"}, {"id": "B", "gold": 50, "items": [], "label": "Gold only"}], "Druid": [{"id": "A", "gold": 9, "items": ["leather_armor", "shield", "quarterstaff", "dagger"], "label": "Leather, shield & staff"}, {"id": "B", "gold": 50, "items": [], "label": "Gold only"}], "Rogue": [{"id": "A", "gold": 8, "items": ["leather_armor", "dagger", "dagger", "shortsword", "shortbow", "arrows"], "label": "Leather, blades & bow"}, {"id": "B", "gold": 100, "items": [], "label": "Gold only"}], "Cleric": [{"id": "A", "gold": 7, "items": ["chain_shirt", "shield", "mace"], "label": "Chain shirt, shield & mace"}, {"id": "B", "gold": 110, "items": [], "label": "Gold only"}], "Ranger": [{"id": "A", "gold": 7, "items": ["studded_leather", "shortsword", "shortsword", "longbow", "arrows"], "label": "Studded leather & bow"}, {"id": "B", "gold": 150, "items": [], "label": "Gold only"}], "Wizard": [{"id": "A", "gold": 5, "items": ["quarterstaff", "dagger", "dagger"], "label": "Staff & daggers"}, {"id": "B", "gold": 55, "items": [], "label": "Gold only"}], "Fighter": [{"id": "A", "gold": 4, "items": ["chain_mail", "greataxe", "mace", "handaxe"], "label": "Heavy melee"}, {"id": "B", "gold": 11, "items": ["studded_leather", "shortsword", "shortsword", "longbow", "arrows"