INSERT INTO campaigns (id, name, visibility, data, name_overridden) VALUES ('sandbox', 'The Testing Grounds', 'private', '{"gameStart": "A clinical stone dungeon built to stress-test every rule of combat. Step inside and begin.", "worldName": "The Testing Grounds", "narratives": {"noLoot": ["Nothing here to take."], "levelUp": ["Level up! You grow stronger.", "You feel a surge of power — level gained."], "noEnemy": ["No enemy here."], "killShot": ["The {enemy} falls. +{xp} XP.", "{enemy} is defeated. +{xp} XP.", "Down goes the {enemy}. +{xp} XP."], "combatHit": {"low": ["A glancing blow, but it counts.", "You scrape past the {enemy}''s guard."], "mid": ["Your attack connects. The {enemy} is hurt.", "You land a solid blow on the {enemy}."], "high": ["A decisive strike — the enemy staggers.", "Clean hit. The {enemy} reels."]}, "classStyle": {"Rogue": ["from the shadows", "finding the gap in their guard", "with practiced efficiency"], "Cleric": ["invoking divine power", "with righteous force", "guided by faith"], "Ranger": ["with hunter''s instinct", "with practiced aim", "reading the terrain"], "Wizard": ["channeling arcane energy", "with calculated intent", "augmented by magic"], "Fighter": ["with disciplined form", "with martial precision", "leveraging years of training"]}, "combatMiss": {"low": ["You swing wide.", "The attack fails to connect."], "mid": ["Attack misses.", "The {enemy} deflects your strike."], "high": ["Your attack goes wide. The {enemy} is fast.", "Near miss — the {enemy} dodges."]}, "deathLines": ["Slain by {enemy}. The dungeon claims another soul.", "The darkness of {world} takes you."], "alreadyDead": ["The remains of your foe lie still."], "roomArrival": {"exit_gate": ["The gate. So close."], "bone_crypt": ["The dead stir as you enter."], "entry_hall": ["You stand at the entrance. The dungeon awaits."], "great_hall": ["Something large moves in the shadows."], "guard_post": ["A goblin sentry spots you immediately."], "storage_room": ["Quiet. You can rest here."], "cultist_chamber": ["Candlelight flickers across a robed figure."]}, "weaponVerbs": {"mace": ["bludgeons with", "slams", "swings"], "dagger": ["stabs with", "drives", "flicks"], "rapier": ["thrusts with", "lunges with", "parries then drives"], "handaxe": ["hurls", "chops with", "swings"], "longbow": ["fires", "looses", "shoots"], "shortbow": ["fires", "looses an arrow with", "shoots"], "longsword": ["swings", "cleaves with", "drives"], "greatsword": ["cleaves with", "brings down", "sweeps"], "shortsword": ["slashes with", "drives", "cuts with"], "quarterstaff": ["strikes with", "sweeps", "thrusts"], "plus1_longsword": ["swings the gleaming blade", "drives the magical sword", "cleaves with"]}, "enemyAttacks": ["The {enemy} strikes back for {dmg} damage.", "The {enemy} retaliates — {dmg} damage.", "{enemy} attacks: {dmg} damage."], "lootPickedUp": ["You pick up the {item}.", "You take the {item}."], "sneakSuccess": ["You slip past the {enemy} undetected."], "alreadyLooted": ["Already taken."], "enemyDeflected": ["The {enemy} swings — deflected by your {armor}!", "Your {armor} turns the {enemy}''s blow."], "enemyReactions": {"Orc": ["roars", "bellows", "lets out a war cry"], "Ogre": ["bellows", "slams its fists together", "stomps the ground"], "Skeleton": ["rattles its bones", "clacks its jaw", "advances silently"], "Goblin Warrior": ["shrieks", "snarls", "snaps its teeth", "chatters angrily"], "Cultist Fanatic": ["mutters a dark prayer", "snarls with zealous fury", "raises a dagger"]}, "genericArrival": ["You move into the room, senses alert.", "The room opens before you.", "You enter cautiously."], "deathSaveStatus": {"1": ["Clinging to life."], "2": ["One foot in the grave."], "3": ["Stable — but unconscious."]}}, "backgrounds": [{"id": "soldier", "desc": "You have served in an organized military force.", "name": "Soldier", "feature": "Military Rank", "language": "Common", "originFeat": "savage_attacker", "featureDesc": "Soldiers and veterans recognize your authority.", "toolProficiency": "Gaming set", "skillProficiencies": ["athletics", "intimidation"], "abilityScoreIncreases": ["str", "dex", "con"]}, {"id": "criminal", "desc": "You have a history of breaking the law.", "name": "Criminal", "feature": "Criminal Contact", "language": "Thieves'' Cant", "originFeat": "alert", "featureDesc": "You have a contact who can help you find information or fences stolen goods.", "toolProficiency": "Thieves'' Tools", "skillProficiencies": ["stealth", "deception"], "abilityScoreIncreases": ["dex", "con", "int"]}, {"id": "sage", "desc": "You spent years learning the lore of the multiverse.", "name": "Sage", "feature": "Researcher", "language": "Common", "originFeat": "magic_initiate_arcane", "featureDesc": "If you do not know information, you know where to find it.", "toolProficiency": "Calligrapher''s Tools", "skillProficiencies": ["arcana", "history"], "abilityScoreIncreases": ["con", "int", "wis"]}, {"id": "acolyte", "desc": "You have spent your life in service to a temple.", "name": "Acolyte", "feature": "Shelter of the Faithful", "language": "Celestial", "originFeat": "magic_initiate_divine", "featureDesc": "You and your companions can receive healing and care at temples.", "toolProficiency": "Calligrapher''s Tools", "skillProficiencies": ["religion", "insight"], "abilityScoreIncreases": ["int", "wis", "cha"]}], "classSpells": {"Bard": ["charm_person", "healing_word", "sleep", "hold_person"], "Druid": ["shillelagh", "entangle", "cure_wounds", "healing_word"], "Cleric": ["sacred_flame", "cure_wounds", "guiding_bolt", "hold_person", "bless", "spiritual_weapon", "animate_dead"], "Ranger": ["cure_wounds", "entangle"], "Wizard": ["fire_bolt", "magic_missile", "thunderwave", "misty_step", "fireball", "animate_dead"], "Paladin": ["bless", "cure_wounds", "guiding_bolt"], "Warlock": ["eldritch_blast", "hex", "charm_person"], "Sorcerer": ["fire_bolt", "sleep", "burning_hands", "misty_step", "fireball"]}, "classStartingLoot": {"B