INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','millhaven_square','0','Malgovia','The Old Road brings you into Malgovia. Millhaven lies to the west; the pine-dark hills hide darker places — and the pass and grove lie beyond.','5','[[{}]]','0','0','[]',NULL,NULL,'f','[]','[]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','millhaven_temple','1','Temple of Selûne','A modest stone temple, its silver crescent glinting above the door. Candles burn within.','5','[[{}, {}, {}, {}, {}, {}, {}], [{}, {"t": "garden"}, {}, {"t": "cobblestone"}, {}, {"t": "garden"}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}]]','3','6','[{"pos": {"x": 3, "y": 0}, "label": "Step back into Millhaven", "ascends": true}]',NULL,NULL,'t','[]','[]','[{"ac": 11, "hp": 8, "id": "npc_sister_maren", "xp": 0, "pos": {"x": 3, "y": 2}, "icon": "prayer", "name": "Sister Maren", "toHit": 2, "damage": "1d4", "attitude": "friendly", "greeting": "Selûne''s blessing upon you, traveler. The crypt to the north — something evil has taken root there. I need brave souls to descend and cleanse it.", "responses": [{"label": "Tell me about the crypt.", "reply": "It is the Shattered Crypt. A lich was sealed within long ago. The Crypt Lord must be destroyed.", "responses": [{"label": "Who was the lich in life?", "reply": "A noble of the Third Age who bargained with death to outlive his line. The bargain kept his body — not his soul."}, {"label": "How do I destroy it?", "reply": "Strike down its body and the phylactery shatters with it. Bring radiance — the dead fear Selûne''s light."}], "consequences": [{"type": "advance_quest", "stepId": "step_learn_crypt", "questId": "quest_crypt"}]}, {"label": "I will clear the crypt.", "reply": "Bless you. The moonstone amulet within is sacred to Selûne — please return it.", "consequences": [{"type": "advance_quest", "stepId": "step_learn_crypt", "questId": "quest_crypt"}]}, {"label": "Can you heal my wounds?", "reply": "For a small donation to the temple, yes.", "consequences": [{"type": "modify_hp", "amount": 8}]}], "persuasionDC": 10}]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','millhaven_market','2','Merchant District','Guild warehouses and market stalls. Aldric the Merchant holds court here.','5','[[{}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {"t": "garden"}, {}, {"t": "cobblestone"}, {}, {"t": "garden"}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}]]','3','6','[{"pos": {"x": 3, "y": 0}, "label": "Step back into Millhaven", "ascends": true}]',NULL,NULL,'f','[]','[]','[{"ac": 10, "hp": 4, "id": "npc_aldric", "xp": 0, "pos": {"x": 3, "y": 2}, "icon": "shop", "name": "Aldric the Merchant", "shop": [{"price": 50, "itemId": "healing_potion"}], "toHit": 0, "damage": "1d4", "attitude": "friendly", "greeting": "Thank the gods — capable folk! Two of our supply wagons vanished on the Old Road three days past. I''ll pay well for anyone who finds what happened to them and recovers the shipping ledger.", "factionId": "faction_guild", "responses": [{"label": "I''ll look into the missing shipment.", "reply": "Wonderful! The ledger would prove our goods were never delivered — the Guild needs it to claim compensation.", "consequences": [{"type": "advance_quest", "stepId": "step_talk_aldric", "questId": "quest_shipment"}]}, {"label": "What do you know about the crypt?", "reply": "Nothing good. Locals avoid it. Word is, something stirs within — lights at night, groaning sounds."}], "persuasionDC": 12}]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','millhaven_lantern','3','Lantern District','Narrow alleys and shuttered windows. Someone is watching from the shadows.','5','[[{}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}]]','3','6','[{"pos": {"x": 3, "y": 0}, "label": "Step back into Millhaven", "ascends": true}]',NULL,NULL,'f','[]','[]','[{"ac": 13, "hp": 14, "id": "npc_dusk", "xp": 0, "pos": {"x": 5, "y": 2}, "name": "Dusk", "toHit": 4, "damage": "1d6+2", "attitude": "indifferent", "greeting": "Eyes down, stranger. If it''s trouble with the Watch, we might have common cause.", "responses": [{"label": "Tell me about the City Watch.", "reply": "Captain Vane''s rotten from the boots up. I have proof — or I will, if you can get into his office.", "consequences": [{"type": "advance_quest", "stepId": "step_meet_dusk", "questId": "quest_shadow"}]}, {"label": "What do you need me to do?", "reply": "Vane keeps a letter in his strongbox at the garrison. Bring it to me.", "consequences": [{"type": "advance_quest", "stepId": "step_meet_dusk", "questId": "quest_shadow"}]}, {"label": "Not interested.", "reply": "Your loss. Don''t say I didn''t offer."}], "proper_noun": true, "persuasionDC": 14}]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','millhaven_garrison','4','Garrison Office','A stone building bearing the City Watch crest. A strongbox sits behind the desk.','5','[[{}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}]]','3','6','[{"pos": {"x": 3, "y": 0}, "label": "Step back into Millhaven", "ascends": true}]',NULL,NULL,'f','[]','[]','[]',NULL,NULL,NULL,NULL,'[{"id": "captain_strongbox", "pos": {"x": 3, "y": 2}, "desc": "An iron strongbox bolted under the captain''s desk. The lock is intricate.", "name": "Captain''s Strongbox", "lootIds": ["shadow_evidence"], "searchDC": 15, "emptyText": "The lock resists you. Reset your tools and try again.", "foundText": "The lock clicks. Inside, the incriminating letter — proof Captain Vane was on the bandits'' payroll.", "searchable": true, "interactText": "You crouch beside the strongbox and work the lock."}]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','old_road','5','The Old Road','A rutted track through the hills. Fresh wagon tracks veer off near a stand of dead trees — and the men who made them are still here.','5','[[{"t": "hills"}, {}, {}, {}, {}, {}, {}, {}, {}, {"t": "hills"}], [{}, {}, {}, {"t": "forest"}, {"t": "forest"}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {"t": "forest"}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{"t": "road"}, {"t": "road"}, {"t": "road"}, {"t": "road"}, {"t": "road"}, {"t": "road"}, {"t": "road"}, {"t": "road"}, {"t": "road"}, {"t": "road"}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {"t": "forest"}, {"t": "forest"}, {}], [{"t": "hills"}, {}, {}, {}, {}, {}, {}, {}, {}, {"t": "hills"}]]','0','4','[{"pos": {"x": 9, "y": 4}, "label": "Press on down the road", "ascends": true}]',NULL,NULL,'f','[{"name": "Bandit Ruffian", "count": 2, "drops": ["dagger"], "goldDrop": 8}]','[]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','dungeon_crypt_entrance','6','Crypt Entrance','Crumbling stone steps lead down. Crude graffiti warns: "Abandon hope." Torch brackets line the walls.','5','[[{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "cobblestone"}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {}, {}, {"t": "mountain"}, {"t": "mountain"}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {"t": "mountain"}, {}, {}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {}, {}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 9, "y": 0}, "label": "Into the antechamber", "toRoomId": "dungeon_antechamber", "entrancePos": {"x": 0, "y": 0}}, {"pos": {"x": 0, "y": 9}, "label": "Climb out to the Old Road", "ascends": true}]','dim',NULL,'f','[]','[]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','dungeon_antechamber','7','Antechamber','A vaulted chamber of black stone. Funeral urns line the alcoves, some shattered. Bones litter the floor.','5','[[{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {"t": "cobblestone"}, {}, {}], [{}, {}, {}, {"t": "mountain"}, {"t": "mountain"}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {"t": "cobblestone"}, {}, {}, {}, {}], [{}, {}, {"t": "cobblestone"}, {}, {}, {}, {"t": "mountain"}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 0, "y": 9}, "label": "Back to the entrance", "toRoomId": "dungeon_crypt_entrance", "entrancePos": {"x": 9, "y": 0}}, {"pos": {"x": 9, "y": 0}, "label": "Charnel Hall", "toRoomId": "dungeon_charnel_hall", "entrancePos": {"x": 0, "y": 0}}, {"pos": {"x": 9, "y": 9}, "label": "Chamber of Offerings", "toRoomId": "dungeon_offering_chamber", "entrancePos": {"x": 0, "y": 0}}]','dark',NULL,'f','[{"id": "dungeon_antechamber#0", "name": "Skeleton Warrior", "count": 1, "goldDrop": 3}]','[{"pos": {"x": 5, "y": 5}, "itemId": "healing_potion"}, {"pos": {"x": 7, "y": 3}, "itemId": "healing_potion"}]','[]',NULL,NULL,NULL,NULL,'[{"id": "funeral_urns", "pos": {"x": 2, "y": 7}, "desc": "Black ceramic urns sealed with wax. Most are cracked open.", "name": "Funeral Urns", "lootIds": ["healing_potion"], "searchDC": 10, "emptyText": "Ashes drift through your fingers. Steady your hand and search again.", "foundText": "Beneath the ashes — a small vial wrapped in cloth. A healing potion!", "searchable": true, "interactText": "You sift through the urns, brushing aside dust and ash."}]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','dungeon_charnel_hall','8','Charnel Hall','A long corridor flanked by sealed burial niches. The seals on several niches have been broken from within. Loose flagstones in the middle of the hall give you pause.','5','[[{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {"t": "mountain"}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {"t": "mountain"}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 0, "y": 9}, "label": "Back to the antechamber", "toRoomId": "dungeon_antechamber", "entrancePos": {"x": 9, "y": 0}}, {"pos": {"x": 9, "y": 9}, "label": "Shadow Gallery", "toRoomId": "dungeon_shadow_gallery", "entrancePos": {"x": 0, "y": 0}}]','dark',NULL,'f','[{"name": "Skeleton Warrior", "count": 2, "goldDrop": 3}]','[]','[]',NULL,NULL,NULL,NULL,'[]','{"dc": 13, "id": "charnel_hall_blade", "desc": "A subtle depression in the flagstones, connected to a spring-loaded blade in the wall.", "name": "Hidden Blade Plate", "damage": "2d6", "damageType": "slashing", "disarmFail": "You misjudge the angle — the mechanism trips and the blade scythes anyway!", "disarmSuccess": "You wedge a fragment of bone into the mechanism. The blade is jammed.", "detectNarrative": "You notice scoring in the wall opposite a worn flagstone — a blade trap, set to scythe across the corridor.", "triggerNarrative": "A blade scythes from the niche-wall! {name} takes {dmg} slashing damage."}');
