INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','dungeon_crypt_throne','12','Throne of the Dead','A massive chamber with a raised dais. An ancient throne of black stone dominates the room. Broken funeral pillars and piles of bone offer fragile cover. Something powerful waits here.','5','[[{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {"t": "cobblestone"}, {}, {}, {"t": "cobblestone"}, {}], [{}, {"t": "cobblestone"}, {}, {}, {}, {"t": "cobblestone"}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {"m": "obstacle", "t": "mountain"}, {}, {}, {}, {"m": "obstacle", "t": "mountain"}, {}, {}], [{}, {}, {}, {}, {"m": "difficult"}, {"m": "difficult"}, {"m": "difficult"}, {}, {}, {}], [{}, {}, {}, {}, {"m": "obstacle", "t": "mountain"}, {}, {"m": "obstacle", "t": "mountain"}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {"t": "cobblestone"}, {}, {}, {}, {}, {}, {}, {"t": "cobblestone"}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}]]','1','1','[{"pos": {"x": 0, "y": 9}, "label": "Back to the Shadow Gallery", "toRoomId": "dungeon_shadow_gallery", "entrancePos": {"x": 9, "y": 9}}, {"pos": {"x": 9, "y": 0}, "label": "Back to the Ossuary", "toRoomId": "dungeon_ossuary", "entrancePos": {"x": 9, "y": 9}}, {"pos": {"x": 9, "y": 9}, "label": "A hidden passage in the dais", "toRoomId": "dungeon_crypt_exit", "entrancePos": {"x": 0, "y": 0}}]','dim',NULL,'f','[{"id": "dungeon_crypt_throne#0", "name": "Crypt Lord", "count": 1, "drops": ["healing_potion", "healing_potion"], "goldDrop": 120}, {"id": "dungeon_crypt_throne#minion_a", "name": "Skeleton Warrior", "count": 1, "goldDrop": 3}]','[{"pos": {"x": 5, "y": 8}, "itemId": "moonstone_amulet"}]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','dungeon_crypt_exit','13','Hidden Passage','A narrow shaft cuts upward through the rock, emerging near the crypt entrance above.','5','[[{}, {}, {}, {}, {}, {}, {}, {}], [{}, {"t": "cobblestone"}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "cobblestone"}, {}, {}, {}, {}, {}], [{}, {}, {}, {"t": "mountain"}, {}, {}, {}, {}], [{}, {}, {}, {}, {"t": "mountain"}, {}, {}, {}], [{}, {}, {}, {}, {}, {"t": "cobblestone"}, {}, {}], [{}, {}, {}, {}, {}, {}, {"t": "cobblestone"}, {}], [{}, {}, {}, {}, {}, {}, {"t": "cobblestone"}, {}]]','0','0','[{"pos": {"x": 0, "y": 1}, "label": "Back down to the throne", "toRoomId": "dungeon_crypt_throne", "entrancePos": {"x": 9, "y": 9}}, {"pos": {"x": 7, "y": 7}, "label": "Climb out to the surface", "ascends": true}]',NULL,NULL,'f','[]','[]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','bandit_camp','14','Bandit Camp','A clearing ringed with crude tents and a smoldering cookfire. A half-stripped merchant wagon lists against a stump, Guild crates scattered around it. Lookouts turn at your approach.','5','[[{}, {}, {}, {"t": "forest"}, {}, {}, {"t": "forest"}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "forest"}, {}, {}, {}, {}, {"t": "forest"}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {"t": "forest"}], [{}, {}, {}, {}, {"t": "mountain"}, {"t": "mountain"}, {}, {}, {}, {}], [{}, {}, {}, {}, {"t": "mountain"}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {"t": "mountain"}, {}, {}, {"t": "forest"}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 9, "y": 9}, "label": "The Captain''s Tent", "toRoomId": "bandit_tent", "entrancePos": {"x": 0, "y": 0}}, {"pos": {"x": 0, "y": 9}, "label": "Leave the camp", "ascends": true}]','dim',NULL,'f','[{"name": "Bandit Ruffian", "count": 2, "drops": ["dagger"], "goldDrop": 9}, {"id": "bandit_camp#2", "name": "Bandit Bowman", "count": 1, "drops": ["shortsword"], "goldDrop": 10}]','[{"pos": {"x": 5, "y": 5}, "itemId": "healing_potion"}]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','bandit_tent','15','Captain''s Tent','A larger oilcloth tent at the camp''s heart. A war-map and a strongbox sit on a crate table. The Bandit Captain rises, hand on hilt.','5','[[{}, {}, {}, {}, {}, {}, {}, {"t": "forest"}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {"t": "mountain"}, {"t": "mountain"}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{"t": "forest"}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 7, "y": 7}, "label": "Back out to the camp", "toRoomId": "bandit_camp", "entrancePos": {"x": 9, "y": 9}}]','dim',NULL,'f','[{"id": "bandit_tent#0", "name": "Bandit Captain", "count": 1, "drops": ["studded_leather", "healing_potion"], "goldDrop": 60}, {"id": "bandit_tent#1", "name": "Bandit Ruffian", "count": 1, "drops": ["dagger"], "goldDrop": 9}]','[{"pos": {"x": 4, "y": 4}, "itemId": "stolen_shipment"}]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','pines_tavern','16','Pine Tavern','A low-beamed inn smelling of woodsmoke and mulled spirits. Innkeeper Brann tends the bar.','5','[[{}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {"t": "snow"}, {}, {"t": "snow"}, {}, {}]]','3','6','[{"pos": {"x": 3, "y": 0}, "label": "Back into the village", "ascends": true}]',NULL,NULL,'t','[]','[]','[{"ac": 10, "hp": 6, "id": "npc_brann", "xp": 0, "pos": {"x": 2, "y": 2}, "icon": "beer-stein", "name": "Innkeeper Brann", "shop": [{"price": 20, "itemId": "elixir_of_warmth"}, {"price": 40, "itemId": "fur_cloak"}], "toHit": 0, "damage": "1d4", "attitude": "friendly", "greeting": "Thank the gods you''re here. Old Halden the trapper went up the pass three days back — never came down. Bring him back, or proof. I''ll pay.", "factionId": "faction_wardens", "responses": [{"label": "I''ll search the pass for Halden.", "reply": "Bless you. His daughter''s been crying herself to sleep. He carries a silver locket — bring it back if you find him."}, {"label": "What about the spire?", "reply": "Iceshard Spire. Cultists. Green fire in the topmost window. Captain Riese knows more."}], "persuasionDC": 10}]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','pines_lodge','17','Trapper''s Lodge','Marta''s lodge — pelts hanging in racks, snowshoes and warhammers along the wall. A locked supply locker stands by the door.','5','[[{}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {"t": "snow"}, {}, {"t": "snow"}, {}, {}]]','3','6','[{"pos": {"x": 3, "y": 0}, "label": "Back into the village", "ascends": true}]',NULL,NULL,'f','[]','[]','[{"ac": 13, "hp": 12, "id": "npc_marta", "xp": 0, "pos": {"x": 4, "y": 2}, "icon": "backpack", "name": "Marta the Trapper", "shop": [{"price": 30, "itemId": "warhammer"}, {"price": 50, "itemId": "longbow"}, {"price": 45, "itemId": "leather_armor"}, {"price": 18, "itemId": "elixir_of_warmth"}], "toHit": 3, "damage": "1d6+2", "attitude": "friendly", "greeting": "Halden was a friend. Take what you need — warhammers work better than blades on the mephits. Carry torches.", "factionId": "faction_wardens", "responses": [{"label": "Tell me about the mephits.", "reply": "Cold breath. Wear your cloak. They flee fire like cats from water."}], "persuasionDC": 11}]',NULL,NULL,NULL,NULL,'[{"id": "trapper_locker", "pos": {"x": 3, "y": 2}, "desc": "Marta''s supply locker, kept off the floor. The lock looks honest, not warded.", "name": "Trapper''s Locker", "lootIds": ["elixir_of_warmth"], "searchDC": 12, "emptyText": "The latch sticks. Brace it properly and try the lock again.", "foundText": "Inside: a wax-stoppered vial. An elixir of warmth.", "searchable": true, "interactText": "You crouch by the locker and pick at the latch."}]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','pines_warden','18','Warden Post','Captain Riese''s command — a stone hut warmed by a single brazier. A war map covers one wall.','5','[[{}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {"t": "snow"}, {}, {"t": "snow"}, {}, {}]]','3','6','[{"pos": {"x": 3, "y": 0}, "label": "Back into the village", "ascends": true}]',NULL,NULL,'f','[]','[]','[{"ac": 16, "hp": 22, "id": "npc_riese", "xp": 0, "pos": {"x": 3, "y": 2}, "icon": "spartan-helmet", "name": "Captain Riese", "toHit": 5, "damage": "1d8+3", "attitude": "indifferent", "greeting": "Listen — the trapper''s a sideshow. The real problem is the cult at Iceshard. Bring back their idol so I know how bad it''s gotten. Kill their leader and we end this for a generation.", "responses": [{"label": "I''ll end the cult at the spire.", "reply": "Good. The Acolyte will be at the top. Bring back the idol."}, {"label": "What about the cult?", "reply": "They worship something old in the ice. Take fire if you have it."}, {"label": "A healer?", "reply": "We''ve a field medic, yes. It''ll cost you, mind.", "consequences": [{"type": "modify_hp", "amount": 6}]}], "persuasionDC": 13}]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','pass_climb','19','Frozen Pass','A switchback trail along the cliff face. Wind carries the scent of woodsmoke from below and something colder from above.','5','[[{}, {}, {}, {"t": "mountain"}, {"t": "mountain"}, {"t": "mountain"}, {"t": "mountain"}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {"t": "mountain"}, {}, {}, {}, {}], [{}, {"t": "snow"}, {"t": "snow"}, {}, {}, {}, {}, {"t": "snow"}, {}, {}], [{}, {}, {"t": "snow"}, {"t": "snow"}, {}, {}, {"t": "snow"}, {"t": "snow"}, {}, {}], [{}, {}, {}, {"t": "snow"}, {"t": "mountain"}, {}, {"t": "snow"}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {"t": "mountain"}, {"t": "mountain"}, {"t": "mountain"}, {"t": "mountain"}, {}, {}, {}]]','0','4','[{"pos": {"x": 9, "y": 4}, "label": "Back down the pass", "ascends": true}]',NULL,NULL,'f','[{"name": "Frost Wolf", "count": 2}]','[]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','spire_entrance','20','Spire Entrance','A black stone arch leans against the cliff. Old cult sigils mark the lintel. The air inside is colder than the wind.','5','[[{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {"t": "snow"}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "snow"}, {}, {}, {}, {}, {"t": "snow"}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {"t": "mountain"}, {"t": "mountain"}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {"t": "mountain"}, {}, {}, {}, {}], [{}, {}, {"t": "snow"}, {}, {}, {}, {}, {"t": "snow"}, {}, {}], [{}, {}, {}, {}, {}, {}, {"t": "water"}, {}, {}, {}], [{}, {}, {}, {"t": "snow"}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 9, "y": 0}, "label": "Into the Frozen Hall", "toRoomId": "spire_frozen_hall", "entrancePos": {"x": 0, "y": 0}}, {"pos": {"x": 0, "y": 9}, "label": "Back out to the pass", "ascends": true}]','dim',NULL,'f','[]','[{"pos": {"x": 5, "y": 5}, "itemId": "fur_cloak"}]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','spire_frozen_hall','21','Frozen Hall','A long pillared hall sheathed in ice. Frost mephits glitter in the air like motes of dust. Heavy icicles hang from the vaulted ceiling — some look ready to fall.','5','[[{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {"t": "snow"}, {}, {}, {}, {}, {}, {}, {"t": "snow"}, {}], [{}, {}, {}, {}, {}, {"t": "snow"}, {}, {}, {}, {}], [{}, {}, {}, {"t": "mountain"}, {}, {}, {"t": "mountain"}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "snow"}, {}, {}, {"t": "water"}, {}, {}, {}, {}], [{}, {}, {}, {"t": "mountain"}, {}, {}, {"t": "mountain"}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {"t": "snow"}, {}, {}, {}, {}, {}, {}, {"t": "snow"}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 0, "y": 1}, "label": "Back to the entrance", "toRoomId": "spire_entrance", "entrancePos": {"x": 9, "y": 0}}, {"pos": {"x": 9, "y": 9}, "label": "Into the Cult Chamber", "toRoomId": "spire_cult_chamber", "entrancePos": {"x": 0, "y": 0}}]','dark',NULL,'f','[{"name": "Ice Mephit", "count": 2}]','[{"pos": {"x": 5, "y": 5}, "itemId": "elixir_of_warmth"}]','[]',NULL,NULL,NULL,NULL,'[]','{"dc": 12, "id": "frozen_hall_icicle", "desc": "A spear-length icicle hangs over the hall, threaded with a thawing rune. Disturbance below shakes it loose.", "name": "Falling Icicle", "damage": "2d6", "damageType": "piercing", "disarmFail": "Your hand slips on the rime — the icicle plummets early!", "disarmSuccess": "You snap the rune cleanly. The icicle slumps harmlessly.", "detectNarrative": "You spot the rune carved at the base of the icicle — pure ice, set to drop if the hall is disturbed.", "triggerNarrative": "The icicle plunges from the ceiling — {name} takes {dmg} piercing damage and a faceful of frost."}');
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','spire_cult_chamber','22','Cult Chamber','A circular vault with a low altar of black ironwood. Frostspire cultists chant in unison around a captive form. (Old Halden lies bound near the altar, unconscious.)','5','[[{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "snow"}, {}, {}, {"t": "water"}, {}, {"t": "snow"}, {}, {}], [{}, {}, {}, {"t": "mountain"}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {"t": "mountain"}, {"t": "mountain"}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {"t": "mountain"}, {}, {}], [{}, {}, {"t": "snow"}, {}, {}, {}, {}, {"t": "snow"}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 0, "y": 1}, "label": "Back to the Frozen Hall", "toRoomId": "spire_frozen_hall", "entrancePos": {"x": 9, "y": 9}}, {"pos": {"x": 9, "y": 9}, "label": "Up to the Ritual Apex", "toRoomId": "spire_ritual_apex", "entrancePos": {"x": 1, "y": 1}}]','dim',NULL,'f','[{"name": "Frost Cultist", "count": 2}]','[{"pos": {"x": 5, "y": 5}, "itemId": "halden_locket"}]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','spire_ritual_apex','23','Ritual Apex','The spire''s top chamber. A green flame burns above the broken vault. Shattered ice columns and frozen statuary line the approach. The Frost Acolyte stands at the apex, hands raised, runes blazing.','5','[[{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {"t": "snow"}, {"t": "snow"}, {}, {}, {}, {}, {}, {"t": "snow"}, {}], [{}, {}, {}, {}, {}, {"m": "obstacle", "t": "mountain"}, {}, {}, {}, {}], [{}, {}, {"m": "obstacle", "t": "mountain"}, {}, {"m": "difficult"}, {"m": "difficult"}, {"m": "difficult"}, {}, {"m": "obstacle", "t": "mountain"}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {"m": "obstacle", "t": "mountain"}, {}, {"m": "obstacle", "t": "mountain"}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {"t": "snow"}, {}, {}, {}, {"t": "snow"}, {}, {}, {"t": "snow"}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}]]','1','1','[{"pos": {"x": 0, "y": 9}, "label": "Back to the Cult Chamber", "toRoomId": "spire_cult_chamber", "entrancePos": {"x": 9, "y": 9}}, {"pos": {"x": 9, "y": 9}, "label": "A hidden descent", "toRoomId": "spire_egress", "entrancePos": {"x": 0, "y": 0}}]','bright',NULL,'f','[{"id": "spire_ritual_apex#boss", "name": "Frost Acolyte", "count": 1}]','[{"pos": {"x": 5, "y": 8}, "itemId": "cult_idol"}]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','spire_egress','24','Hidden Descent','A narrow stair cuts through the cliff back to the lower trail. Daylight shows below.','5','[[{}, {}, {}, {}, {}, {}, {}, {}], [{}, {"t": "snow"}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "snow"}, {}, {}, {}, {}, {}], [{}, {}, {}, {"t": "mountain"}, {}, {}, {}, {}], [{}, {}, {}, {}, {"t": "mountain"}, {}, {}, {}], [{}, {}, {}, {}, {}, {"t": "snow"}, {}, {}], [{}, {}, {}, {}, {}, {}, {"t": "snow"}, {}], [{}, {}, {}, {}, {}, {}, {"t": "snow"}, {}]]','0','0','[{"pos": {"x": 0, "y": 1}, "label": "Back up to the apex", "toRoomId": "spire_ritual_apex", "entrancePos": {"x": 9, "y": 9}}, {"pos": {"x": 7, "y": 7}, "label": "Descend to the pass", "ascends": true}]',NULL,NULL,'f','[]','[]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','pinegate_square','25','Pinegate Village','A small village square with a stone well at its center. Pine trees rise dark beyond the houses. Lanterns burn even at midday.','5','[[{"t": "garden"}, {}, {}, {}, {}, {}, {"t": "garden"}], [{}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{"t": "garden"}, {}, {"t": "cobblestone"}, {"t": "water"}, {"t": "cobblestone"}, {}, {"t": "garden"}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{"t": "garden"}, {}, {}, {"t": "cobblestone"}, {}, {}, {"t": "garden"}]]','3','6','[{"pos": {"x": 3, "y": 0}, "label": "Back into Pinegate", "ascends": true}]',NULL,'dirt','f','[]','[]','[{"ac": 10, "hp": 6, "id": "npc_elise_elder", "xp": 0, "pos": {"x": 3, "y": 2}, "icon": "sprite:pawn_yellow_idle", "name": "Old Elise (village elder)", "toHit": 0, "damage": "1d4", "attitude": "friendly", "greeting": "Mother Mareth went into the grove two weeks ago and never returned. The beasts have gone savage. We need someone — anyone — to walk the path she walked.", "factionId": "faction_verdant", "responses": [{"label": "We''ll find Mareth and the grove''s heart.", "reply": "Bless you. Take her charm from the lodge — it will let the Oak know you are no enemy. Defeat the Fey Trickster at the heart and the grove will mend.", "consequences": [{"type": "advance_quest", "stepId": "step_talk_elise", "questId": "quest_silent_grove"}]}, {"label": "What do you know about this Fey Trickster?", "reply": "A Sidhe creature. It charms first, kills second. Don''t look it in the eye. Mareth must have refused its bargain. Hex magic is its mark."}, {"label": "Mareth made deals with fey before?", "reply": "The Verdant Circle works with old powers, but this one came uninvited. Whatever pact it offered, Mareth refused — that is why the grove is in pain."}], "persuasionDC": 10}, {"ac": 11, "hp": 10, "id": "npc_bram_woodcutter", "xp": 0, "pos": {"x": 5, "y": 4}, "icon": "sprite:pawn_blue_axe_idle", "name": "Bram the Woodcutter", "toHit": 2, "damage": "1d6", "attitude": "friendly", "greeting": "Mind the treeline, friend — the pines have gone wrong of late. I keep my axe close and my eyes closer.", "responses": [{"label": "What have you seen in the woods?", "reply": "Shapes that don''t cast shadows. Thorns where the path was. I won''t go past the old marker stone anymore."}, {"label": "Safe travels, then.", "reply": "Aye. Keep to the light."}], "persuasionDC": 10}]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','pinegate_lodge','26','The Burnt Stump (lodge)','A timber-frame lodge serving as inn, common-hall, and informal council seat. A fire crackles. Mareth''s carved charm hangs on the wall.','5','[[{}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}], [{}, {}, {}, {"t": "cobblestone"}, {}, {}, {}]]','3','6','[{"pos": {"x": 3, "y": 0}, "label": "Back into Pinegate", "ascends": true}]',NULL,NULL,'f','[]','[{"pos": {"x": 3, "y": 2}, "itemId": "circle_charm"}]','[{"ac": 11, "hp": 8, "id": "npc_tamsin_herbalist", "xp": 0, "pos": {"x": 4, "y": 2}, "icon": "health-potion", "name": "Tamsin the Herbalist", "shop": [{"price": 50, "itemId": "healing_potion"}], "toHit": 1, "damage": "1d4", "attitude": "friendly", "greeting": "Welcome. The grove has not yielded medicine in weeks — what I have left, I sell. Circle-members get a fair price.", "factionId": "faction_verdant", "responses": [{"label": "What can you tell me about the grove?", "reply": "The Ancient Oak is at the heart. Mareth used to commune with it. If you reach it and the Oak still lives, plant her charm at its roots — the grove will know."}], "persuasionDC": 10}]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','thornwater_bridge','27','Thornwater Bridge','A stone bridge across rushing water. The pines on the far bank stand too still. A faded Verdant Circle banner hangs from the rail.','5','[[{}, {"t": "forest"}, {"t": "forest"}, {"t": "forest"}, {"t": "forest"}, {"t": "forest"}, {"t": "forest"}, {"t": "forest"}], [{}, {"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}], [{}, {"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}], [{"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}, {"t": "cobblestone"}], [{"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}], [{"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}, {"t": "water"}]]','0','3','[{"pos": {"x": 7, "y": 3}, "label": "Cross into the grove", "toRoomId": "grove_entrance", "entrancePos": {"x": 0, "y": 0}}, {"pos": {"x": 0, "y": 0}, "label": "Back to the Verdant Reach", "ascends": true}]',NULL,NULL,'f','[]','[]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','grove_entrance','28','Grove Entrance','The path widens into a clearing of standing stones. Wolf-eyes glow from the underbrush. The Circle''s old gateway arch is here — and broken.','5','[[{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "forest"}, {"t": "forest"}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {"t": "forest"}, {"t": "forest"}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {"t": "garden"}, {"t": "garden"}, {}, {}, {"t": "forest"}, {}], [{}, {"t": "forest"}, {}, {}, {"t": "garden"}, {"t": "garden"}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {"t": "forest"}, {}, {}], [{}, {}, {"t": "forest"}, {"t": "forest"}, {}, {}, {"t": "forest"}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 0, "y": 1}, "label": "Back to the bridge", "toRoomId": "thornwater_bridge", "entrancePos": {"x": 7, "y": 3}}, {"pos": {"x": 9, "y": 9}, "label": "Into the Thornwood", "toRoomId": "thornwood_maze", "entrancePos": {"x": 0, "y": 0}}]',NULL,'grass','f','[{"name": "Awakened Wolf", "count": 2}]','[]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','thornwood_maze','29','The Thornwood Maze','A winding stretch of thorn-thicket where the path forks and rejoins. Webs glint between branches. Something many-legged moves overhead.','5','[[{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "forest"}, {"t": "forest"}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {"t": "forest"}, {}, {}, {}], [{}, {"t": "forest"}, {}, {}, {"t": "forest"}, {}, {}, {}, {"t": "forest"}, {}], [{}, {}, {"t": "swamp"}, {}, {}, {}, {"t": "forest"}, {"t": "swamp"}, {}, {}], [{}, {}, {"t": "forest"}, {}, {}, {"t": "forest"}, {}, {}, {}, {}], [{}, {}, {}, {}, {"t": "forest"}, {}, {}, {"t": "forest"}, {}, {}], [{}, {}, {}, {"t": "forest"}, {}, {"t": "swamp"}, {}, {}, {"t": "forest"}, {}], [{}, {"t": "forest"}, {}, {}, {}, {"t": "forest"}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 0, "y": 1}, "label": "Back to the entrance", "toRoomId": "grove_entrance", "entrancePos": {"x": 9, "y": 9}}, {"pos": {"x": 9, "y": 9}, "label": "To the Ancient Oak", "toRoomId": "ancient_oak", "entrancePos": {"x": 1, "y": 1}}]',NULL,NULL,'f','[{"name": "Giant Spider", "count": 2}]','[]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','ancient_oak','30','The Ancient Oak','A vast, ancient oak at the grove''s heart. Roots curl up from the earth in a circular dais, splitting the approach into braided paths. A figure in fey green stands at the trunk — the Trickster, with two trained bears flanking it.','5','[[{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {"t": "forest"}, {}, {}, {}, {}, {}, {"t": "forest"}, {}], [{}, {}, {}, {}, {"m": "obstacle"}, {}, {"m": "obstacle"}, {}, {}, {}], [{}, {}, {}, {}, {"t": "garden"}, {"m": "difficult", "t": "garden"}, {"t": "garden"}, {}, {}, {}], [{}, {}, {}, {"m": "obstacle"}, {"m": "difficult", "t": "garden"}, {"m": "difficult", "t": "garden"}, {"m": "difficult", "t": "garden"}, {"m": "obstacle"}, {}, {}], [{}, {}, {}, {}, {"t": "garden"}, {"m": "obstacle"}, {"t": "garden"}, {}, {}, {}], [{}, {"t": "forest"}, {}, {}, {}, {"t": "garden"}, {}, {}, {"t": "forest"}, {}], [{}, {}, {"t": "forest"}, {}, {}, {}, {}, {"t": "forest"}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}, {}, {}]]','1','1','[{"pos": {"x": 0, "y": 9}, "label": "Back into the maze", "toRoomId": "thornwood_maze", "entrancePos": {"x": 9, "y": 9}}, {"pos": {"x": 9, "y": 9}, "label": "Into the sanctum", "toRoomId": "grove_sanctum", "entrancePos": {"x": 0, "y": 0}}]',NULL,NULL,'f','[{"id": "ancient_oak#0", "name": "Fey Trickster", "count": 1}, {"id": "ancient_oak#1", "name": "Thornbound Wolf", "count": 1}]','[]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('malgovia','grove_sanctum','31','Grove Sanctum','A sunlit clearing past the Oak. Mareth''s charm warms in your hand. The path back to Pinegate is open.','5','[[{}, {}, {}, {}, {}, {}, {}, {}], [{}, {"t": "forest"}, {}, {}, {}, {}, {"t": "forest"}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {"t": "garden"}, {"t": "garden"}, {"t": "garden"}, {}, {}], [{}, {}, {"t": "garden"}, {"t": "garden"}, {"t": "garden"}, {}, {}, {}], [{}, {}, {}, {}, {"t": "garden"}, {}, {"t": "forest"}, {}], [{}, {"t": "forest"}, {"t": "forest"}, {}, {}, {}, {"t": "forest"}, {}], [{}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 0, "y": 1}, "label": "Back to the Oak", "toRoomId": "ancient_oak", "entrancePos": {"x": 9, "y": 9}}, {"pos": {"x": 7, "y": 7}, "label": "Return to Pinegate", "ascends": true}]',NULL,'grass','f','[]','[{"pos": {"x": 4, "y": 4}, "itemId": "oak_heart"}]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('sandbox','entry_hall','0','Entry Hall','A torchlit stone corridor. Crumbling archways lead deeper into the dungeon. A weapon rack on the wall holds a dusty blade.','5','[[{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 7, "y": 0}, "label": "Deeper in", "toRoomId": "guard_post", "entrancePos": {"x": 0, "y": 0}}, {"pos": {"x": 0, "y": 7}, "label": "Leave the dungeon", "ascends": true}]',NULL,NULL,'f','[]','[]','[]',NULL,NULL,NULL,NULL,'[{"id": "weapon_rack", "desc": "A rusted iron rack holding an assortment of old weapons.", "name": "Weapon Rack", "lootIds": ["dagger"], "searchDC": 10, "emptyText": "You miss it on the first pass. Look again.", "foundText": "Beneath the rust, a serviceable dagger.", "searchable": true, "interactText": "You examine the weapon rack."}]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('sandbox','guard_post','1','Guard Post','A crude goblin sentry post. Alarm bells hang from a string across the doorway. Crossbow bolts are scattered on the floor.','5','[[{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 0, "y": 1}, "label": "Back to the entry hall", "toRoomId": "entry_hall", "entrancePos": {"x": 7, "y": 0}}, {"pos": {"x": 7, "y": 7}, "label": "Into the crypt", "toRoomId": "bone_crypt", "entrancePos": {"x": 0, "y": 0}}]',NULL,NULL,'f','[{"id": "guard_post#0", "name": "Goblin Warrior", "count": 1}]','[]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('sandbox','bone_crypt','2','Bone Crypt','Shelves carved into the walls hold hundreds of bones. The air is deathly still.','5','[[{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 0, "y": 1}, "label": "Back to the guard post", "toRoomId": "guard_post", "entrancePos": {"x": 7, "y": 7}}, {"pos": {"x": 7, "y": 7}, "label": "Through to storage", "toRoomId": "storage_room", "entrancePos": {"x": 0, "y": 0}}]',NULL,NULL,'f','[{"id": "bone_crypt#0", "name": "Skeleton", "count": 1}]','[]','[]',NULL,NULL,NULL,NULL,'[]','{"dc": 13, "id": "pressure_plate", "desc": "A subtle depression in the floor stone, connected to a spring-loaded spear mechanism.", "name": "Pressure Plate", "damage": "2d6", "damageType": "piercing", "disarmFail": "Your attempt to jam the mechanism fails — it triggers! Spears slam from the walls.", "disarmSuccess": "With careful hands, you jam the mechanism. The trap is disabled.", "detectNarrative": "You spot a slight discoloration in the floor stones — a pressure plate. Stepping on it would be bad.", "triggerNarrative": "A plate depresses underfoot — spears erupt from the walls! {name} takes {dmg} piercing damage."}');
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('sandbox','storage_room','3','Storage Room','Barrels and crates are stacked against the walls. The room is quiet — a rare moment of safety.','5','[[{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 0, "y": 1}, "label": "Back to the crypt", "toRoomId": "bone_crypt", "entrancePos": {"x": 7, "y": 7}}, {"pos": {"x": 7, "y": 7}, "label": "Into the great hall", "toRoomId": "great_hall", "entrancePos": {"x": 0, "y": 0}}]',NULL,NULL,'t','[]','[]','[]',NULL,NULL,NULL,NULL,'[{"id": "supply_crate", "desc": "A heavy wooden crate, sealed with iron bands.", "name": "Supply Crate", "lootIds": ["healing_potion"], "searchDC": 10, "emptyText": "The lid jams. Get a better grip and try again.", "foundText": "Inside: a vial of red liquid. A healing potion.", "searchable": true, "interactText": "You pry open the crate."}]',NULL);
