INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('sandbox','cultist_chamber','5','Cultist Chamber','Ritual candles surround a dark altar. A robed figure turns to face you, eyes wild with fervor.','5','[[{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 0, "y": 1}, "label": "Back to the great hall", "toRoomId": "great_hall", "entrancePos": {"x": 7, "y": 7}}, {"pos": {"x": 7, "y": 0}, "label": "Toward the gate", "toRoomId": "exit_gate", "entrancePos": {"x": 0, "y": 0}}]',NULL,NULL,'f','[{"id": "cultist_chamber#0", "name": "Cultist Fanatic", "count": 1}]','[]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
INSERT INTO campaign_rooms (campaign_id,id,sort_order,name,description,feet_per_square,grid,entry_x,entry_y,exits,lighting,floor,can_rest,enemies,loot,npcs,on_enter,on_first_enter,on_exit,on_first_exit,objects,trap) VALUES ('sandbox','exit_gate','6','Exit Gate','Iron-banded doors stand at the far end of the chamber. Freedom — if you can reach it.','5','[[{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}], [{}, {}, {}, {}, {}, {}, {}, {}]]','0','0','[{"pos": {"x": 0, "y": 1}, "label": "Back to the cultist chamber", "toRoomId": "cultist_chamber", "entrancePos": {"x": 7, "y": 0}}, {"pos": {"x": 7, "y": 7}, "label": "Force the gate — leave the dungeon", "ascends": true}]',NULL,NULL,'f','[]','[]','[]',NULL,NULL,NULL,NULL,'[]',NULL);
