INSERT INTO campaign_custom_items (campaign_id,item_id,sort_order,definition) VALUES ('malgovia','elixir_of_warmth','5','{"id": "elixir_of_warmth", "desc": "A clay vial of mulled spirits brewed by the trappers. Restores 1d4+2 HP and steadies the body against cold.", "heal": "1d4+2", "name": "Elixir of Warmth", "slot": null, "type": "consumable", "damage": null, "effect": null, "weight": 1, "aliases": ["elixir", "mulled spirit"], "ac_bonus": null}');
