INSERT INTO campaign_custom_monsters (campaign_id,monster_id,sort_order,definition) VALUES ('malgovia','crypt-lord','3','{"ac": 17, "cr": 5, "hp": 97, "xp": 1800, "cha": 16, "con": 18, "dex": 10, "int": 11, "str": 18, "wis": 10, "name": "Crypt Lord", "drops": ["healing_potion", "healing_potion"], "toHit": 7, "damage": "2d6+4", "phases": [{"name": "Wrath of the Sealed Tomb", "hpPct": 50, "effects": [{"kind": "set_to_hit", "value": 9}, {"dice": "2d8+4", "kind": "set_damage"}, {"kind": "set_on_hit_effect", "effect": {"dc": 15, "ability": "wis", "condition": "frightened"}}], "narrative": "Bone splinters erupt from the floor around the Crypt Lord — its eye-sockets blaze. ''You will not silence me again!''"}, {"name": "Phylactery Crack", "hpPct": 25, "effects": [{"kind": "heal", "amount": 25}, {"dice": "3d6+4", "kind": "set_damage"}, {"kind": "set_ac", "value": 18}], "narrative": "A black gem in its breastplate fractures. Necrotic light pours into the Crypt Lord — its wounds knit closed and it lunges with renewed fury."}], "goldDrop": 120, "damageType": "necrotic", "immunities": ["poison", "necrotic"], "multiattack": 2, "onHitEffect": {"dc": 13, "ability": "wis", "condition": "frightened"}, "resistances": ["bludgeoning", "piercing", "slashing"], "condition_immunities": ["charmed", "exhaustion", "frightened", "paralyzed", "poisoned"]}');
