INSERT INTO campaign_custom_monsters (campaign_id,monster_id,sort_order,definition) VALUES ('malgovia','frost-acolyte','10','{"ac": 15, "cr": 1, "hp": 130, "xp": 2900, "name": "Frost Acolyte", "toHit": 7, "damage": "2d6+4", "phases": [{"name": "Ice Armor", "hpPct": 60, "effects": [{"kind": "set_ac", "value": 17}, {"dice": "2d10+4", "kind": "set_damage"}], "narrative": "The Acolyte hisses a hard syllable and frost rimes their robes — blows skid off. Around them the ritual flame burns colder."}, {"name": "Frostbinding", "hpPct": 30, "effects": [{"kind": "set_to_hit", "value": 8}, {"kind": "set_multiattack", "value": 3}, {"kind": "set_on_hit_effect", "effect": {"dc": 16, "ability": "con", "condition": "paralyzed"}}], "narrative": "The Acolyte tears off their frost cloak. Black ice spreads beneath their feet. Their staff lashes with bone-cold speed."}], "immunities": ["poison"], "multiattack": 2, "onHitEffect": {"dc": 14, "ability": "con", "condition": "paralyzed"}, "resistances": ["cold"], "vulnerabilities": ["fire"], "condition_immunities": ["frightened", "paralyzed"]}');
